Measuring the latency from the signal generation timestamp to the exchange acknowledgment is crucial for understanding the performance and reliability of your trading system. Here’s a step-by-step guide on how you can measure this latency:

### Step 1: Signal Generation Timestamp

Capture the exact time when a trading signal is generated.

```python
import datetime

def generate_signal(data_feed):
    # Generate signal logic here
    timestamp = datetime.datetime.now()

    if condition:
        return 'buy', timestamp

    elif other_condition:
        return 'sell', timestamp

    else:
        return None, timestamp
```

### Step 2: Order Execution Timestamp

Capture the exact time when an order is sent to the exchange.

```python
import datetime

class OrderExecution(bt.Strategy):
    def __init__(self, signals):
        self.signals = signals
        self.order_timestamps = {}

    def next(self):
        for signal in self.signals:
            if signal == 'buy':
                timestamp = datetime.datetime.now()
                order_id = self.buy(size=position_size)
                self.order_timestamps[order_id] = (timestamp, 'buy')

            elif signal == 'sell':
                timestamp = datetime.datetime.now()
                order_id = self.sell(size=position_size)
                self.order_timestamps[order_id] = (timestamp, 'sell')

    def notify_order(self, order):
        if order.status in [bt.Order.Completed]:
            acknowledgment_time = datetime.datetime.now()
            signal_time, action = self.order_timestamps.get(order.ref, (None, None))

            if signal_time is not None:
                latency = acknowledgment_time - signal_time
                print(f"Latency for {action} order: {latency}")
```

